import{_ as t,c as i,o as a,ag as e}from"./chunks/framework.DK1-H3E1.js";const p=JSON.parse('{"title":"Agent 开发：从单轮问答到可执行智能体","description":"","frontmatter":{"order":11},"headers":[],"relativePath":"ai/agent-development.md","filePath":"ai/agent-development.md","lastUpdated":1772197851000}'),r={name:"ai/agent-development.md"};function n(o,l,s,d,h,g){return a(),i("div",null,l[0]||(l[0]=[e('<h1 id="agent-开发-从单轮问答到可执行智能体" tabindex="-1">Agent 开发：从单轮问答到可执行智能体 <a class="header-anchor" href="#agent-开发-从单轮问答到可执行智能体" aria-label="Permalink to &quot;Agent 开发：从单轮问答到可执行智能体&quot;">​</a></h1><blockquote><p>📅 主题：Agent 架构、规划执行、记忆与评估</p></blockquote><h2 id="一、什么是-agent" tabindex="-1">一、什么是 Agent <a class="header-anchor" href="#一、什么是-agent" aria-label="Permalink to &quot;一、什么是 Agent&quot;">​</a></h2><p>在 LLM 场景里，<strong>Agent（智能体）</strong> 通常指：</p><ul><li>能理解目标（而不只是回答一个问题）</li><li>能调用工具（搜索、代码执行、API、数据库等）</li><li>能分解任务并迭代执行</li><li>能基于中间结果继续决策</li></ul><p>所以 Agent 不只是“会聊天的模型”，而是一个「<strong>模型 + 工具 + 工作流 + 状态</strong>」的系统。</p><p>一句话：<strong>LLM 提供推理与生成，Agent 提供行动与闭环。</strong></p><hr><h2 id="二、agent-与传统-prompt-应用的区别" tabindex="-1">二、Agent 与传统 Prompt 应用的区别 <a class="header-anchor" href="#二、agent-与传统-prompt-应用的区别" aria-label="Permalink to &quot;二、Agent 与传统 Prompt 应用的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>传统 Prompt 应用</th><th>Agent 应用</th></tr></thead><tbody><tr><td>任务粒度</td><td>单轮或少轮问答</td><td>多步骤目标驱动</td></tr><tr><td>外部能力</td><td>很少或固定</td><td>按需调用多工具</td></tr><tr><td>状态管理</td><td>基本无状态</td><td>维护上下文、记忆、任务进度</td></tr><tr><td>失败处理</td><td>用户重试</td><td>具备重试、回滚、替代策略</td></tr><tr><td>结果形态</td><td>一段文本</td><td>文本 + 操作结果 + 结构化输出</td></tr></tbody></table><p>这也是为什么 Agent 开发往往更像“后端系统开发”，而不仅是 Prompt 调优。</p><hr><h2 id="三、典型-agent-架构" tabindex="-1">三、典型 Agent 架构 <a class="header-anchor" href="#三、典型-agent-架构" aria-label="Permalink to &quot;三、典型 Agent 架构&quot;">​</a></h2><p>一个常见的工程化 Agent，通常包含以下模块：</p><ol><li><p><strong>Planner（规划器）</strong></p><ul><li>把用户目标拆成子任务（例如：先检索资料 → 再分析 → 再输出报告）</li></ul></li><li><p><strong>Executor（执行器）</strong></p><ul><li>实际执行步骤，调用工具或子 Agent</li></ul></li><li><p><strong>Tool Router（工具路由）</strong></p><ul><li>决定当前步骤该用哪个工具，并做参数校验</li></ul></li><li><p><strong>Memory（记忆）</strong></p><ul><li>短期记忆：当前会话上下文</li><li>长期记忆：用户偏好、历史任务结论、知识沉淀</li></ul></li><li><p><strong>State / Store（状态存储）</strong></p><ul><li>记录任务状态、中间结果、重试次数、日志</li></ul></li><li><p><strong>Guardrail（安全护栏）</strong></p><ul><li>权限控制、敏感操作确认、输出合规检查</li></ul></li><li><p><strong>Evaluator（评估器）</strong></p><ul><li>检查结果是否达标，不达标则触发修正或重试</li></ul></li></ol><hr><h2 id="四、核心能力设计" tabindex="-1">四、核心能力设计 <a class="header-anchor" href="#四、核心能力设计" aria-label="Permalink to &quot;四、核心能力设计&quot;">​</a></h2><h3 id="_4-1-规划与分解" tabindex="-1">4.1 规划与分解 <a class="header-anchor" href="#_4-1-规划与分解" aria-label="Permalink to &quot;4.1 规划与分解&quot;">​</a></h3><p>Agent 要做复杂任务时，应先明确：</p><ul><li>目标是什么（输出格式、成功标准）</li><li>子任务顺序（串行/并行）</li><li>每个子任务依赖什么数据</li></ul><p>可选策略：</p><ul><li><strong>一步步规划（Plan-then-Execute）</strong>：先出计划再执行，适合任务清晰、可审计场景</li><li><strong>边想边做（ReAct 风格）</strong>：推理与行动交替，适合动态环境和探索型任务</li></ul><h3 id="_4-2-工具调用" tabindex="-1">4.2 工具调用 <a class="header-anchor" href="#_4-2-工具调用" aria-label="Permalink to &quot;4.2 工具调用&quot;">​</a></h3><p>工具调用是 Agent 开发的关键。实践上建议：</p><ul><li>工具输入输出尽量结构化（JSON Schema）</li><li>调用前做参数验证（类型、范围、权限）</li><li>失败时提供重试策略与降级路径</li><li>对副作用操作（写库、发消息、执行命令）加确认机制</li></ul><h3 id="_4-3-记忆设计" tabindex="-1">4.3 记忆设计 <a class="header-anchor" href="#_4-3-记忆设计" aria-label="Permalink to &quot;4.3 记忆设计&quot;">​</a></h3><p>可把记忆分三层：</p><ul><li><strong>会话记忆</strong>：当前任务中的中间过程（短期）</li><li><strong>用户记忆</strong>：偏好、背景、长期目标（长期）</li><li><strong>知识记忆</strong>：文档、经验、SOP（通常通过 RAG/索引读取）</li></ul><p>记忆要可追溯、可更新、可删除，避免“积累脏上下文”。</p><h3 id="_4-4-反思与纠错" tabindex="-1">4.4 反思与纠错 <a class="header-anchor" href="#_4-4-反思与纠错" aria-label="Permalink to &quot;4.4 反思与纠错&quot;">​</a></h3><p>成熟 Agent 不应一次失败就结束，通常要有：</p><ul><li>结果自检（是否满足约束）</li><li>失败分类（工具错误、检索不足、推理错误）</li><li>自我修正（补检索、换工具、重写方案）</li></ul><p>这类闭环可显著提升复杂任务的稳定性。</p><hr><h2 id="五、agent-开发流程-实战建议" tabindex="-1">五、Agent 开发流程（实战建议） <a class="header-anchor" href="#五、agent-开发流程-实战建议" aria-label="Permalink to &quot;五、Agent 开发流程（实战建议）&quot;">​</a></h2><h3 id="阶段-1-先做单任务-mvp" tabindex="-1">阶段 1：先做单任务 MVP <a class="header-anchor" href="#阶段-1-先做单任务-mvp" aria-label="Permalink to &quot;阶段 1：先做单任务 MVP&quot;">​</a></h3><p>选一个高频且明确的场景，比如：</p><ul><li>文档问答 Agent</li><li>PR 变更解读 Agent</li><li>日报/周报生成 Agent</li></ul><p>先完成“从输入到可用输出”的闭环，不要一上来追求全能。</p><h3 id="阶段-2-引入工具与数据" tabindex="-1">阶段 2：引入工具与数据 <a class="header-anchor" href="#阶段-2-引入工具与数据" aria-label="Permalink to &quot;阶段 2：引入工具与数据&quot;">​</a></h3><ul><li>接入检索（RAG）</li><li>接入外部工具（API、数据库、文件系统）</li><li>打通基础权限与审计</li></ul><h3 id="阶段-3-增加规划与状态管理" tabindex="-1">阶段 3：增加规划与状态管理 <a class="header-anchor" href="#阶段-3-增加规划与状态管理" aria-label="Permalink to &quot;阶段 3：增加规划与状态管理&quot;">​</a></h3><ul><li>拆分步骤</li><li>记录状态与中间结果</li><li>增加重试与超时控制</li></ul><h3 id="阶段-4-加评估与护栏" tabindex="-1">阶段 4：加评估与护栏 <a class="header-anchor" href="#阶段-4-加评估与护栏" aria-label="Permalink to &quot;阶段 4：加评估与护栏&quot;">​</a></h3><ul><li>结果质量评估（准确率、引用率、任务完成率）</li><li>安全检查（敏感词、越权、数据泄露）</li><li>人在回路（高风险步骤需人工确认）</li></ul><hr><h2 id="六、与-rag、mcp、skills-的配合" tabindex="-1">六、与 RAG、MCP、Skills 的配合 <a class="header-anchor" href="#六、与-rag、mcp、skills-的配合" aria-label="Permalink to &quot;六、与 RAG、MCP、Skills 的配合&quot;">​</a></h2><ul><li><p><strong>RAG</strong>：解决“Agent 知识从哪来”</p><ul><li>在每个步骤前按需检索，减少幻觉</li><li>参考文档可要求输出引用</li></ul></li><li><p><strong>MCP</strong>：解决“Agent 能调用哪些能力”</p><ul><li>通过标准协议接入工具与资源</li><li>让 Agent 能跨系统执行动作</li></ul></li><li><p><strong>Skills / Agent Skills</strong>：解决“Agent 应该怎么做”</p><ul><li>把流程、规范、模板封装成可复用技能</li><li>降低行为漂移，提高一致性</li></ul></li></ul><p>可以理解为：</p><ul><li>RAG = 知识层</li><li>MCP = 能力层</li><li>Skills = 策略层</li><li>Agent = 决策与执行层</li></ul><hr><h2 id="七、常见坑与规避" tabindex="-1">七、常见坑与规避 <a class="header-anchor" href="#七、常见坑与规避" aria-label="Permalink to &quot;七、常见坑与规避&quot;">​</a></h2><ol><li><p><strong>提示词堆砌但无状态管理</strong></p><ul><li>规避：建立明确 state，记录每一步输入输出</li></ul></li><li><p><strong>工具很多但不会选</strong></p><ul><li>规避：加工具路由与工具描述规范，限制默认可用集合</li></ul></li><li><p><strong>上下文爆炸</strong></p><ul><li>规避：做上下文裁剪、摘要与优先级管理</li></ul></li><li><p><strong>无评估只看“感觉可用”</strong></p><ul><li>规避：定义可量化指标（完成率、错误率、平均耗时）</li></ul></li><li><p><strong>高风险操作无护栏</strong></p><ul><li>规避：权限分级 + 人工确认 + 操作日志</li></ul></li></ol><hr><h2 id="八、小结" tabindex="-1">八、小结 <a class="header-anchor" href="#八、小结" aria-label="Permalink to &quot;八、小结&quot;">​</a></h2><ol><li>Agent 开发本质是系统工程：<strong>模型 + 工具 + 状态 + 护栏 + 评估</strong>。</li><li>从单任务 MVP 起步，逐步增加工具、记忆、规划和评估，比一次性做“大而全”更稳。</li><li>工程落地重点不是“模型有多强”，而是“流程是否可控、可观测、可迭代”。</li><li>与 RAG、MCP、Skills 结合后，Agent 才能形成完整生产力闭环。</li></ol><p>当你把 Agent 当成一个可演进的产品来做，而不是一个临时 Prompt，效果通常会发生质变。</p>',57)]))}const c=t(r,[["render",n]]);export{p as __pageData,c as default};
